declare namespace cc {
    export interface PhysicsManager {
        _world: b2.World;
        _registerContactFixture(fixture: b2.Fixture): void;
        _unregisterContactFixture(fixture: b2.Fixture): void;
    }

    export interface PhysicsCollider {
        _shapes: b2.Shape[];
    }

    export interface RigidBody {
        _b2Body: b2.Body;
    }
}

declare namespace b2 {

    export class AABB {
        lowerBound: Vec2;
        upperBound: Vec2;
        IsValid(): boolean;
        GetCenter(): Vec2;
        GetExtents(): Vec2;
        GetPerimeter(): number;
        Combine1(aabb: AABB): void;
        Combine2(aabb1: AABB, aabb2: AABB): void;
        Contains(aabb: AABB): boolean;
        RayCast(output: RayCastOutput, input: RayCastInput): boolean;
        TestOverlap(other: AABB): boolean;
        TestContain(point: Vec2): boolean;
    }

    export class Filter {
        /**
         * 其值为 1 << cc.node.groupIndex
         */
        categoryBits: number;
        maskBits: number;
        groupIndex: number;
    }

    export class Contact {
        GetFixtureA(): Fixture;
        GetFixtureB(): Fixture;
        GetNext(): Contact;
    }

    export class Fixture {
        Refilter(): void;
        GetBody(): Body;
        Refilter(): void;
        GetShape(): Shape;
        GetUserData(): any;
        GetType(): ShapeType;
        GetDensity(): number;
        GetFriction(): number;
        GetRestitution(): number;
        GetFilterData(): Filter;
        IsSensor(): boolean;
        SetSensor(sensor: boolean): void;
        SetUserData(data: any): void;
        SetSensor(sensor: boolean): void;
        SetDensity(density: number): void;
        SetFilterData(filter: Filter): void;
        SetFriction(friction: number): void;
        SetRestitution(restitution: number): void;
    }

    export class ContactFilter {
        ShouldCollide(fixtureA: Fixture, fixtureB: Fixture): boolean;
        ShouldCollideFixtureParticle(fixture: Fixture, particleSystem: ParticleSystem, particleIndex: number): boolean;
        ShouldCollideParticleParticle(particleSystem: ParticleSystem, indexA: number, indexB: number): boolean;
        static b2_defaultFilter?: ContactFilter;
    }

    export class World {
        GetContactList(): Contact;
        GetParticleSystemList(): ParticleSystem;
        SetContactFilter(filter: ContactFilter): void;
        CreateParticleSystem(def: ParticleSystemDef): ParticleSystem;
        DestroyParticleSystem(particleSystem: ParticleSystem): void;
    }

    export class Body {
        IsAwake(): boolean;
        IsActive(): boolean;
        GetAngle(): number;
        GetPosition(): Vec2;
        GetUserData(): any;
        GetLinearVelocity(): Vec2;
        GetFixtureList(): Fixture;
        SetLinearVelocity(v: Vec2): void;
        SetUserData(data: any): void;
        SetPosition(p: Vec2): void;
    }

    export class Vec2 {
        x: number;
        y: number;
        SetZero(): void;
        Set(x: number, y: number): void;
        constructor(x: number, y: number);
    }

    export class Color {
        a: number;
        b: number;
        g: number;
        r: number;
        constructor(r: number, g: number, b: number, a: number);
    }

    export class Rot {
        s: number;
        c: number;
        constructor(s: number, c: number);
    }

    /** 形状类型 */
    export enum ShapeType {
        e_circleShape = 0,
        e_edgeShape = 1,
        e_polygonShape = 2,
        e_chainShape = 3,
        e_shapeTypeCount = 4,
        e_unknown = -1
    }

    /** 形状定义 */
    export class Shape {
        m_type: ShapeType;
        m_radius: number;
        constructor(type: ShapeType, radius: number);
        GetType(): ShapeType;
        Copy(other: Shape): Shape;
    }

    /** 变化 */
    export class Transform {
        p: Vec2;
        q: Rot;
        static IDENTITY: Transform;
        constructor();
        GetAngle(): number;
        GetPosition(): Vec2;
        GetRotation(): Rot;
        GetRotationAngle(): number;
        SetIdentity(): void;
        SetPosition(position: Vec2): void;
        SetPositionAngle(position: Vec2, angle: number): void;
        SetPositionRotation(position: Vec2, rotation: Rot): void;
        SetRotation(rotation: Rot): void;
        SetRotationAngle(radians: number): void;
    }

    /** 粒子类型*/
    export enum ParticleFlag {
        /** 水粒子 */
        b2_waterParticle = 0,
        /** 僵尸粒子 */
        b2_zombieParticle = 1 << 1,
        /** 墙粒子 */
        b2_wallParticle = 1 << 2,
        /** 弹簧粒子 */
        b2_springParticle = 1 << 3,
        /** 弹性粒子 */
        b2_elasticParticle = 1 << 4,
        /** 粘性粒子 */
        b2_viscousParticle = 1 << 5,
        /** 粉末粒子 */
        b2_powderParticle = 1 << 6,
        /** 拉伸粒子 */
        b2_tensileParticle = 1 << 7,
        /** 颜色混合粒子 */
        b2_colorMixingParticle = 1 << 8,
        /** 粒子销毁监听器 */
        b2_destructionListenerParticle = 1 << 9,
        /** 粒子屏障 */
        b2_barrierParticle = 1 << 10,
        /** 静态压力粒子 */
        b2_staticPressureParticle = 1 << 11,
        /** 反应粒子 */
        b2_reactiveParticle = 1 << 12,
        /** 排斥粒子 */
        b2_repulsiveParticle = 1 << 13,
        /** 夹具接触监听器粒子 */
        b2_fixtureContactListenerParticle = 1 << 14,
        /** 粒子接触监听器粒子 */
        b2_particleContactListenerParticle = 1 << 15,
        /** 夹具接触过滤器粒子 */
        b2_fixtureContactFilterParticle = 1 << 16,
        /** 粒子接触过滤器粒子 */
        b2_particleContactFilterParticle = 1 << 17
    }

    /** 粒子群组类型 */
    export enum ParticleGroupFlag {
        b2_solidParticleGroup = 1 << 0,
        b2_rigidParticleGroup = 1 << 1,
        b2_particleGroupCanBeEmpty = 1 << 2,
        b2_particleGroupWillBeDestroyed = 1 << 3,
        b2_particleGroupNeedsUpdateDepth = 1 << 4
    }

    /** 粒子定义 */
    export class ParticleDef {
        flags: ParticleFlag;
        position: Vec2;
        velocity: Vec2;
        color: Color;
        lifetime: number;
        userData: any;
        group: ParticleGroup;
    }


    /** 粒子组定义 */
    export class ParticleGroupDef {
        flags: ParticleFlag;
        groupFlags: ParticleGroupFlag;
        position: Vec2;
        angle: number;
        linearVelocity: Vec2;
        angularVelocity: number;
        color: Color;
        strength: number;
        shape: Shape;
        shapes: Shape[];
        shapeCount: number;
        stride: number;
        particleCount: number;
        positionData: Vec2[];
        lifetime: number;
        userData: any;
        group: ParticleGroup;
    }

    /** 粒子系统定义 */
    export class ParticleSystemDef {
        strictContactCheck: boolean;
        density: number;
        gravityScale: number;
        radius: number;
        maxCount: number;
        pressureStrength: number;
        dampingStrength: number;
        elasticStrength: number;
        springStrength: number;
        viscousStrength: number;
        surfaceTensionPressureStrength: number;
        surfaceTensionNormalStrength: number;
        repulsiveStrength: number;
        powderStrength: number;
        ejectionStrength: number;
        staticPressureStrength: number;
        staticPressureRelaxation: number;
        staticPressureIterations: number;
        colorMixingStrength: number;
        destroyByAge: boolean;
        lifetimeGranularity: number;
    }


    /** 粒子组 */
    export class ParticleGroup {
        ApplyForce(force: Vec2): void;
        ApplyLinearImpulse(impulse: Vec2): void;
        ContainsParticle(index: number): boolean;
        DestroyParticles(callDestructionListener: boolean): void;
        GetAllParticleFlags(): ParticleFlag;
        GetAngle(): number;
        GetAngularVelocity(): number;
        GetBufferIndex(): number;
        GetCenter(): Vec2;
        GetGroupFlags(): ParticleGroupFlag;
        GetLinearVelocity(): Vec2;
        GetLinearVelocityFromWorldPoint(worldPoint: Vec2): Vec2;
        GetNext(): ParticleGroup;
        GetMass(): number;
        GetParticleCount(): number;
        GetParticleSystems(): ParticleSystem;
        GetPosition(): Vec2;
        GetTransform(): Transform;
        GetUserData(): any;
        SetGroupFlags(flags: ParticleGroupFlag): void;
        SetUserData(data: any): void;
        UpdateStatistics(): void;
    }

    /** 粒子系统 */
    export class ParticleSystem {
        CreateParticle(def: ParticleDef): number;
        CreateParticleGroup(def: ParticleGroupDef): ParticleGroup;
        CreateParticleForGroup(groupDf: ParticleGroupDef, xf: Transform, p: Vec2): number;
        GetParticleCount(): number;
        GetParticleGroupCount(): number;
        GetParticleGroupList(): ParticleGroup;
        GetPositionBuffer(): Vec2[];
        GetVelocityBuffer(): Vec2[];
        GetColorBuffer(): Color[];
        GetUserDataBuffer(): any[];
        GetWeightBuffer(): number[];
        SetPositionBuffer(buffer: Vec2[], capacity: number): void;
        SetVelocityBuffer(buffer: Vec2[], capacity: number): void;
        SetColorBuffer(buffer: Color[], capacity: number): void;
        SetUserDataBuffer(buffer: any[], capacity: number): void;
        SetRadius(radius: number): void;
        DestroyParticle(index: number, callDestructionListener?: boolean): void;
        DestroyParticlesGroup(group: ParticleGroup): void;
        DestroyParticlesInGroup(group: ParticleGroup, callDestructionListener?: boolean): void;
        constructor(def: ParticleSystemDef, world: World);
    }


}
